using UnityEngine;
public class FiringSystem : MonoBehaviour
{
    [SerializeField] private float currentTemperature;
    [SerializeField] private float temperatureRisePerSecond = 50f;
    [SerializeField] private float windValue = 1f;
    [SerializeField] private float fuelBoost = 200f;
    [SerializeField] private bool isFiring = true;
    [SerializeField] private float normalTempMin = 1000f;
    [SerializeField] private float normalTempMax = 1300f;
    private bool isWindowOpen;
    public enum FireZone { Underfired, Normal, Overfired }
    public float CurrentTemperature
    {
        get { return currentTemperature; }
    }
    public bool IsFiring
    {
        get { return isFiring; }
    }
    public void SetWindValue(float value)
    {
        windValue = Mathf.Clamp01(value);
    }
    public void AddFuel()
    {
        currentTemperature += fuelBoost;
    }
    public bool IsWindowOpen
    {
        get { return isWindowOpen; }
    }
    public void ToggleWindow()
    {
        isWindowOpen = !isWindowOpen;
    }
    public void StopFiring()
    {
        isFiring = false;
        isWindowOpen = true;
    }
    public FireZone GetCurrentZone()
    {
        if (currentTemperature < normalTempMin) return FireZone.Underfired;
        if (currentTemperature > normalTempMax) return FireZone.Overfired;
        return FireZone.Normal;
    }
